            const status =
              t.status === 'not_started' && anyDone ? 'in_progress' : t.status
            return { ...t, steps, status }
          }),
        })),

      setStepValue: (taskId, stepId, value) =>
        set((s) => ({
          tasks: updateTask(s.tasks, taskId, (t) => ({
