            </p>
          </div>
          <div className="space-y-1.5">
            <Label>Default persona</Label>
            <Select value={defaultPersona} onValueChange={(v) => setDefaultPersona(v as Role)}>
              <SelectTrigger>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                {PERSONAS.map((p) => (
                  <SelectItem key={p.value} value={p.value}>
